methods.example:
// Typically you use async/await:
async fn fetch_data() -> String {
    String::from("data")
}

async fn main_task() {
    let data = fetch_data().await;
    println!("{}", data);
}

async fn get_value() -> i32 {
    42
}

async fn example() {
    let val = get_value().await;
    assert_eq!(val, 42);
}

async fn compute() -> i32 {
    let a = fetch_a().await;
    let b = fetch_b().await;
    a + b
}

let future = async {
    let val = some_async_fn().await;
    val + 1
};

// Future<Output = String> means
// this future produces a String
async fn greeting() -> String {
    String::from("hello")
}
